def solve(nums: list[int], k: int) -> list[float]:
    if k <= 0 or k > len(nums):
        return []
    sl = []
    res = []
    for i, v in enumerate(nums):
        bisect.insort(sl, v)
        if i >= k:
            out = nums[i - k]
            idx = bisect.bisect_left(sl, out)
            sl.pop(idx)
        if i >= k - 1:
            if k % 2 == 1:
